"use client";

import { useEffect, useRef } from "react";
import { gsap } from "gsap";

export default function CustomCursor() {
  const cursor = useRef<HTMLDivElement>(null);

  useEffect(() => {
    const move = (e: MouseEvent) => {
      gsap.to(cursor.current, {
        x: e.clientX,
        y: e.clientY,
        duration: 0.15,
      });
    };

    window.addEventListener("mousemove", move);

    const heroTargets = document.querySelectorAll(".cursor-expand");

    heroTargets.forEach((el) => {
      el.addEventListener("mouseenter", () => {
        cursor.current?.classList.add("cursor-large");
      });

      el.addEventListener("mouseleave", () => {
        cursor.current?.classList.remove("cursor-large");
      });
    });

    const socialTargets = document.querySelectorAll(".cursor-ring");

    socialTargets.forEach((el) => {
      el.addEventListener("mouseenter", () => {
        cursor.current?.classList.add("cursor-outline");
      });

      el.addEventListener("mouseleave", () => {
        cursor.current?.classList.remove("cursor-outline");
      });
    });
  }, []);

  return (
    <div
      ref={cursor}
      className="custom-cursor fixed top-0 left-0 w-6 h-6 border border-white rounded-full pointer-events-none z-[999]"
    />
  );
}
